INSERT INTO LOOKUPS VALUES('CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5:AQQAAABFAAAA:112:6','de:Bug','CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5','B0050BXW7W','AQQAAABFAAAA:112','Das war ein Bug.',1767192335340);
INSERT INTO LOOKUPS VALUES('CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2:AUcCAAAIAAAA:2938:6','de:Bug','CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2','B0050BXW7W','AUcCAAAIAAAA:2938','Im Bericht war von einem Bug die Rede, doch im Team sprach zunächst niemand laut darüber.',1767282246613);
INSERT INTO LOOKUPS VALUES('CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5:AZECAAAGAAAA:2210:12','de:Neutrinos','CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5','B0050BXW7W','AZECAAAGAAAA:2210','Die Neutrinos tauchten erst in der Randnotiz auf, als die Messreihe schon fast abgeschlossen war.',1767282213327);
INSERT INTO LOOKUPS VALUES('CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2:AVMCAAAuAAAA:9012:13','de:Panspermie','CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2','B0050BXW7W','AVMCAAAuAAAA:9012',unistr('Im Protokoll stand Panspermie zunächst nur am Rand.\u000a\u000aSpäter tauchte Panspermie auch in der Zusammenfassung auf.'),1767282512968);
INSERT INTO LOOKUPS VALUES('CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5:AWkCAAANAAAA:1444:13','de:Panspermie','CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5','B0050BXW7W','AWkCAAANAAAA:1444','In der Diskussion fiel das Wort Panspermie, und plötzlich nahm die Runde eine unerwartet kosmische Richtung.',1767283416417);
INSERT INTO LOOKUPS VALUES('CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2:AQkBAABYAAAA:2489:12','de:bugsierte','CR!N7O3R9A1F4E8L2D6B5C7H1J9K3P2','B0050BXW7W','AQkBAABYAAAA:2489','Er bugsierte den Wagen rückwärts in die enge Einfahrt, während neben ihm noch zwei Kisten kippten, jemand nach dem Schlüssel suchte und aus dem offenen Fenster schon wieder eine viel zu genaue Anweisung gerufen wurde.',1771060609662);
INSERT INTO LOOKUPS VALUES('CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5:AX4BAAAQAAAA:1882:11','de:Maßstäbe','CR!M4K8A2L1T5A9G3S7D2P6R8N4H1Q5','B0050BXW7W','AX4BAAAQAAAA:1882','Für die neuen Maßstäbe fehlte im Lager noch ein beschriftetes Kästchen; später stand dort nur noch „größer, präziser, weißer“.',1772954949281);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:Ae4BAAAyAAAA:226:9','en:clouds','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B0053VMNYW','Ae4BAAAyAAAA:226','By noon the clouds had thinned enough for the antennas to show again.',1772955662925);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:AUUCAAAXAAAA:2284:9','en:clouds','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B00NM4BKNC','AUUCAAAXAAAA:2284','Low clouds moved across the ridge while the crew checked the lamps one by one.',1773675093002);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:AeABAAASAAAA:4124:12','en:indicated','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B00NM4BKNC','AeABAAASAAAA:4124','A faint mark on the panel indicated where the cover had already been forced open.',1775124659817);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:AwQCAAAkAAAA:4021:14','en:mercenaries','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B00NM4BKNC','AwQCAAAkAAAA:4021','The mercenaries waited by the gate, trading dull jokes and watching the road.',1773073996652);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:AdMBAAAEAAAA:3650:11','en:bulkhead','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B00NM4BKNC','AdMBAAAEAAAA:3650','She set the toolkit against the bulkhead and counted the screws twice.',1773073996651);
INSERT INTO LOOKUPS VALUES('CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7:AUgCAABaAAAA:3252:16','en:reverberating','CR!E5V1A8N4S7H2O6R9T3L5P1Q8D4K7','B00NM4BKNC','AUgCAABaAAAA:3252','The alarm kept reverberating through the lower corridor long after the door was sealed, so every metal step, every clipped order, and every delayed reply seemed to arrive twice.',1774023231859);
